  1→import supabase from "../services/supabase.js";
  2→import { asyncHandler } from "../utils/controllerHandler.js";
  3→import { recordPublishForStreak } from "../services/streakService.js";
  4→
  5→const OPINION_LIST_SELECT = `
  6→    id,
  7→    user_id,
  8→    parent_id,
  9→    opinion,
 10→    reply_count,
 11→    created_at,
 12→    users(name, id, user_email, image_url, badge)
 13→`;
 14→const MY_OPINION_SELECT = `
 15→    id,
 16→    user_id,
 17→    parent_id,
 18→    opinion,
 19→    reply_count,
 20→    created_at
 21→`;
 22→const USER_OPINION_SELECT = `
 23→    id,
 24→    user_id,
 25→    parent_id,
 26→    opinion,
 27→    reply_count,
 28→    created_at,
 29→    users(name, image_url, id, badge)
 30→`;
 31→
 32→const parseOpinionLimit = (raw) => {
 33→    const parsed = parseInt(raw);
 34→    if (isNaN(parsed) || parsed < 1 || parsed > 20) return null;
 35→    return parsed;
 36→};
 37→
 38→export const addOpinionController = asyncHandler(async (req, res) => {
 39→    const { opinion } = req.body;
 40→    if (!opinion || opinion.length > 280) {
 41→        return res.status(400).json({ error: 'no opinion or opinion is over 280 characters' });
 42→    }
 43→    const userId = req.userId;
 44→
 45→    const { error } = await supabase
 46→        .from('opinions')
 47→        .insert({ user_id: userId, opinion });
 48→
 49→    if (error) {
 50→        console.error('supabase error:', error.message);
 51→        return res.status(500).json({ error: 'supabase error' });
 52→    }
 53→
 54→    // Non-fatal: record publish for writing streak
 55→    try {
 56→        recordPublishForStreak(userId).catch(err =>
 57→            console.error('non-fatal: streak record failed:', err?.message || err)
 58→        );
 59→    } catch (streakErr) {
 60→        console.error('non-fatal: streak record failed:', streakErr?.message || streakErr);
 61→    }
 62→
 63→    return res.status(200).json({ message: 'success' });
 64→});
 65→
 66→export const getOpinionsController = asyncHandler(async (req, res) => {
 67→    const { before } = req.query;
 68→    const parsedLimit = parseOpinionLimit(req.query.limit);
 69→    if (parsedLimit == null) {
 70→        return res.status(400).json({ error: 'limit should be number and it should be between 1 - 20' });
 71→    }
 72→
 73→    let query = supabase
 74→        .from('opinions')
 75→        .select(OPINION_LIST_SELECT)
 76→        .is('parent_id', null)
 77→        .order('id', { ascending: false })
 78→        .limit(parsedLimit + 1);
 79→
 80→    if (before) query = query.lt('id', before);
 81→
 82→    const { data: opinions, error } = await query;
 83→    if (error) {
 84→        console.error('supabase error:', error.message);
 85→        return res.status(500).json({ error: 'supabase error on fetching opinions from database' });
 86→    }
 87→
 88→    const hasMore = opinions?.length > parsedLimit;
 89→    const slicedData = hasMore ? opinions.slice(0, parsedLimit) : opinions;
 90→    return res.status(200).json({ data: slicedData, hasMore });
 91→});
 92→
 93→export const getMyOpinionsController = asyncHandler(async (req, res) => {
 94→    const { before } = req.query;
 95→    const parsedLimit = parseOpinionLimit(req.query.limit);
 96→    if (parsedLimit == null) {
 97→        return res.status(400).json({ error: 'limit should be number and between 1 - 20' });
 98→    }
 99→
100→    let query = supabase
101→        .from('opinions')
102→        .select(MY_OPINION_SELECT)
103→        .order('id', { ascending: false })
104→        .limit(parsedLimit + 1)
105→        .eq('user_id', req.userId)
106→        .is('parent_id', null);
107→
108→    if (before) query = query.lt('id', before);
109→
110→    const { data, error } = await query;
111→    if (error) {
112→        console.error('supabase error:', error.message);
113→        return res.status(500).json({ error: 'supabase error while fetching the users opinions' });
114→    }
115→
116→    const hasMore = data.length > parsedLimit;
117→    const slicedData = hasMore ? data.slice(0, parsedLimit) : data;
118→    return res.status(200).json({ data: slicedData, hasMore });
119→});
120→
121→export const getUserOpinionsController = asyncHandler(async (req, res) => {
122→    const { before, userId } = req.query;
123→    const parsedLimit = parseOpinionLimit(req.query.limit);
124→    if (parsedLimit == null) {
125→        return res.status(400).json({ error: 'limit should be number and not be greater than 20 or less than 1' });
126→    }
127→    if (!userId) {
128→        return res.status(400).json({ error: 'no user id available!' });
129→    }
130→
131→    let query = supabase
132→        .from('opinions')
133→        .select(USER_OPINION_SELECT)
134→        .limit(parsedLimit + 1)
135→        .eq('user_id', userId)
136→        .is('parent_id', null)
137→        .order('id', { ascending: false });
138→
139→    if (before) query = query.lt('id', before);
140→
141→    const { data, error } = await query;
142→    if (error) {
143→        console.error('supabase error:', error.message);
144→        return res.status(500).json({ error: 'supabase error while fetching opinions' });
145→    }
146→
147→    const hasMore = data.length > parsedLimit;
148→    const slicedData = hasMore ? data.slice(0, parsedLimit) : data;
149→    return res.status(200).json({ data: slicedData, hasMore });
150→});
